import{c as o,Q as a,j as n,m as r}from"./chunks/framework.Bhbi9jCp.js";const p=JSON.parse('{"title":"实体系统:脱离网格的自由对象","description":"","frontmatter":{},"headers":[],"relativePath":"minecraftLearning/06-实体系统-脱离网格的自由对象.md","filePath":"minecraftLearning/06-实体系统-脱离网格的自由对象.md","lastUpdated":1781674740000}'),s={name:"minecraftLearning/06-实体系统-脱离网格的自由对象.md"};function i(e,t,l,d,u,c){return a(),n("div",null,[...t[0]||(t[0]=[r(`<h1 id="实体系统-脱离网格的自由对象" tabindex="-1">实体系统:脱离网格的自由对象 <a class="header-anchor" href="#实体系统-脱离网格的自由对象" aria-label="Permalink to &quot;实体系统:脱离网格的自由对象&quot;">​</a></h1><p>前面几篇讲的方块,本质都活在一个整数网格里:每个坐标一个格子,格子内容靠在 section 数组里的下标隐含表达,所以千万个石头不需要各自存一份&quot;我在哪&quot;。但 Minecraft 里还有一整套和方块<strong>完全平行</strong>的东西——僵尸、玩家、掉在地上的剑、飞出去的箭、矿车、盔甲架。它们不在网格上,能站在两格之间,能平滑移动,每一个都得单独记住自己的位置。这就是<strong>实体(Entity)</strong>。</p><p>实体和方块是 Minecraft 数据模型的两根独立支柱。最容易踩的坑,就是把它们当成一回事——尤其是&quot;方块实体&quot;这个名字带来的误导(那其实是方块的一部分,不是实体,后面第 09 篇会专门掰开)。这一篇先把&quot;真正的实体&quot;讲透。</p><blockquote><p>一句话先记住:<strong>方块是网格上隐含位置、可共享、几乎无逐实例数据的格子内容;实体是脱离网格、每个都带浮点坐标和自己一份数据、每 tick 都要单独更新的独立对象。</strong> 两套系统平行存在,只在碰撞时才发生交互。</p></blockquote><hr><h2 id="一、本质区别-实体不在网格上" tabindex="-1">一、本质区别:实体不在网格上 <a class="header-anchor" href="#一、本质区别-实体不在网格上" aria-label="Permalink to &quot;一、本质区别:实体不在网格上&quot;">​</a></h2><p>把方块和实体并排看,差别一目了然:</p><table tabindex="0"><thead><tr><th>维度</th><th>方块 / BlockState</th><th>实体 Entity</th></tr></thead><tbody><tr><td>位置</td><td>对齐整数网格,<strong>隐含</strong>(就是数组下标)</td><td><strong>浮点坐标 <code>(x, y, z)</code></strong>,显式存储</td></tr><tr><td>能否在格子之间</td><td>不能,永远占满一格</td><td>能,站在 0.5 格、平滑移动</td></tr><tr><td>逐实例数据</td><td>基本没有(靠 BlockState 共享 + 调色板下标)</td><td><strong>每个都有自己一份</strong>,用 NBT 存</td></tr><tr><td>数量级</td><td>海量(整个世界每格都是)</td><td>少量(在场的怪物、掉落物、玩家)</td></tr><tr><td>更新方式</td><td>被随机刻抽样、被邻居通知</td><td><strong>每个每 tick 都主动更新</strong></td></tr></tbody></table><p>关键点在第一行。方块省就省在&quot;位置不用存、内容能共享&quot;;而实体恰恰反过来——它必须显式记住每个对象在哪、朝哪、速度多少。这决定了实体是<strong>重对象</strong>:在场实体越多,服务端每 tick 要遍历更新的对象就越多。</p><hr><h2 id="二、一个实体身上挂着什么" tabindex="-1">二、一个实体身上挂着什么 <a class="header-anchor" href="#二、一个实体身上挂着什么" aria-label="Permalink to &quot;二、一个实体身上挂着什么&quot;">​</a></h2><p>每个实体都是一个逐实例的重对象,自带这些数据,<strong>全部用 NBT 序列化</strong>进存档:</p><ul><li><strong>UUID</strong>:全局唯一标识。命令选择器 <code>@e</code> 定位、拴绳/坐骑的归属、存档里&quot;这只怪是哪只&quot;,都靠它。</li><li><strong>位置、速度向量、朝向</strong>(yaw/pitch):浮点。速度向量是它能&quot;飞出去&quot;、受重力、被击退的基础。</li><li><strong>AABB 包围盒</strong>(Axis-Aligned Bounding Box):一个轴对齐的长方体,用于碰撞检测(下一节细讲)。</li><li><strong>类型相关数据</strong>:生物有生命值、状态效果、装备、AI 记忆;掉落物有它装着的物品和拾取冷却;箭有伤害值和插入位置;矿车有所在轨道……</li></ul><p>一个掉在地上的剑,它的 ItemStack(剑本身的附魔、耐久等数据)就原样塞在这个实体的 NBT 里——同一份物品数据,在箱子里时挂在方块实体下,扔地上时就挂在实体下(这条会在第 10 篇物品那里再呼应)。</p><hr><h2 id="三、实体的层级" tabindex="-1">三、实体的层级 <a class="header-anchor" href="#三、实体的层级" aria-label="Permalink to &quot;三、实体的层级&quot;">​</a></h2><p>实体不是一锅乱炖,而是一棵继承树,从&quot;能动的东西&quot;逐层细化到&quot;有生命、有 AI、有玩家输入&quot;:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Entity(根:有位置、能移动、能碰撞)</span></span>
<span class="line"><span>├─ LivingEntity(有生命值、能受伤、有状态效果)</span></span>
<span class="line"><span>│   ├─ Mob(有 AI:寻路、目标选择)</span></span>
<span class="line"><span>│   │   ├─ 怪物(僵尸、苦力怕、骷髅…)</span></span>
<span class="line"><span>│   │   └─ 生物(牛、村民、羊…)</span></span>
<span class="line"><span>│   └─ Player(玩家:由网络输入驱动,不跑 AI)</span></span>
<span class="line"><span>├─ 投射物(箭、雪球、末影珍珠…)</span></span>
<span class="line"><span>├─ 掉落物 ItemEntity(地上的一组物品)</span></span>
<span class="line"><span>├─ 载具(矿车、船)</span></span>
<span class="line"><span>└─ 其它(盔甲架、画、经验球、TNT、闪电…)</span></span></code></pre></div><p>读这棵树要抓两条分界:</p><ul><li><strong><code>LivingEntity</code> 这条线</strong>:从这里开始才有&quot;生命值/受伤/状态效果&quot;。盔甲架虽然长得像生物,但它不在这条线上,所以它没有血、不会主动动。</li><li><strong><code>Player</code> 和 <code>Mob</code> 的分叉</strong>:两者都是 LivingEntity,但玩家<strong>不跑 AI</strong>——它的行为由客户端发来的网络输入驱动;Mob 才有寻路和目标选择。这解释了为什么玩家和怪物共享生命/装备/状态效果系统,但玩家从不会&quot;自己走路&quot;。</li></ul><hr><h2 id="四、实体怎么-tick" tabindex="-1">四、实体怎么 tick <a class="header-anchor" href="#四、实体怎么-tick" aria-label="Permalink to &quot;四、实体怎么 tick&quot;">​</a></h2><p>这是实体最吃性能的地方。<strong>每个实体每 tick 都要单独更新一遍</strong>,内容包括重力与碰撞、AI、各种计时(燃烧、窒息、生命恢复、状态效果倒计时)等。</p><h3 id="碰撞-aabb-逐轴裁剪" tabindex="-1">碰撞:AABB 逐轴裁剪 <a class="header-anchor" href="#碰撞-aabb-逐轴裁剪" aria-label="Permalink to &quot;碰撞:AABB 逐轴裁剪&quot;">​</a></h3><p>实体移动不是&quot;瞬移到目标点&quot;,而是:</p><ol><li>算出本 tick 想要的位移向量。</li><li>把位移<strong>拆成 x / y / z 三个轴</strong>,逐轴去和周围方块的 AABB 做重叠检测。</li><li>哪个轴撞上了,就把那个轴的位移<strong>裁剪</strong>到刚好贴着方块表面。</li></ol><p>很多手感细节都是这套逐轴裁剪的副产物:</p><ul><li><strong>贴墙滑行</strong>:你斜着撞墙,垂直墙面的那个轴位移被裁掉,平行墙面的轴保留,于是你顺着墙滑。</li><li><strong>卡角</strong>:两个轴同时被裁、又因为浮点边界反复横跳,就会&quot;卡&quot;在方块角上。</li></ul><h3 id="寻路-a" tabindex="-1">寻路:A* <a class="header-anchor" href="#寻路-a" aria-label="Permalink to &quot;寻路:A\\*&quot;">​</a></h3><p>Mob 找路用 <strong>A*</strong> 在可行走的节点图上搜索,每个节点带通行代价(水、岩浆、危险方块代价高,绕开)。寻路是 AI 里相当贵的操作,<strong>一大群怪同时寻路</strong>会明显吃满 tick 预算。</p><h3 id="ai-goal-与-brain-两套" tabindex="-1">AI:Goal 与 Brain 两套 <a class="header-anchor" href="#ai-goal-与-brain-两套" aria-label="Permalink to &quot;AI:Goal 与 Brain 两套&quot;">​</a></h3><table tabindex="0"><thead><tr><th>AI 系统</th><th>用在谁身上</th><th>特点</th></tr></thead><tbody><tr><td><strong>Goal</strong>(目标优先级选择器)</td><td>多数旧怪物</td><td>一组带优先级的目标(攻击、游荡、看玩家…),每 tick 选择执行</td></tr><tr><td><strong>Brain</strong>(行为 + 记忆 + 感知)</td><td>村民、部分新怪</td><td>行为树 + 记忆 + 传感器,<strong>更重</strong>,能表达&quot;白天上工、晚上回家&quot;这种复杂日程</td></tr></tbody></table><p>Brain 比 Goal 重得多,这也是为什么<strong>一个村庄里堆很多村民会卡服</strong>——每个村民每 tick 都在跑一套带记忆和感知的行为系统。</p><hr><h2 id="五、存储与性能-实体为什么是-lag-头号嫌疑" tabindex="-1">五、存储与性能:实体为什么是 lag 头号嫌疑 <a class="header-anchor" href="#五、存储与性能-实体为什么是-lag-头号嫌疑" aria-label="Permalink to &quot;五、存储与性能:实体为什么是 lag 头号嫌疑&quot;">​</a></h2><ul><li><strong>存哪</strong>:实体属于它当前坐标所在的 chunk,随该 chunk 加载/卸载。<strong>1.17 起实体被单独拆出去</strong>,存到独立的 <code>entities/r.x.z.mca</code>(和方块数据分文件,格式仍是 region)。把实体和方块分开,好处是能在不加载&quot;满功能方块 chunk&quot;的情况下单独处理实体。</li><li><strong>为什么卡</strong>:回到第一节那张表——实体是逐实例、每 tick 全量更新的重对象。<strong>大量掉落物、刷怪笼怪潮、漏斗物流里的物品实体</strong>,会让&quot;实体 tick&quot;这一步直接吃满单 tick 的时间预算,把 TPS 拖下去。优化服务器性能,第一刀几乎总是砍向&quot;在场实体数量&quot;。</li></ul><hr><h2 id="六、反直觉点-实体不-占据-方块格" tabindex="-1">六、反直觉点:实体不&quot;占据&quot;方块格 <a class="header-anchor" href="#六、反直觉点-实体不-占据-方块格" aria-label="Permalink to &quot;六、反直觉点:实体不&quot;占据&quot;方块格&quot;">​</a></h2><p>这是最该记住、也最容易想错的一点:</p><blockquote><p><strong>一只僵尸站在某个坐标上,那个坐标的方块</strong>仍然是空气**。** 僵尸只是一个浮在那里的独立对象,它和&quot;空气方块&quot;是两套系统里的两样东西,谁也不属于谁。</p></blockquote><p>也就是说:</p><ul><li>方块网格不知道&quot;这里站着一只僵尸&quot;;僵尸也不&quot;填进&quot;任何格子。</li><li>两套系统<strong>平行运行</strong>,唯一的交集是<strong>碰撞检测</strong>——实体移动时拿自己的 AABB 去和周围方块的 AABB 比对(第四节那套逐轴裁剪)。除此之外,它们各活各的。</li></ul><p>想通这一点,很多现象就顺了:为什么你能和怪物站在&quot;同一格&quot;、为什么挖掉脚下方块怪会掉下去(碰撞没了)、为什么实体多了卡的是&quot;实体 tick&quot;而不是&quot;方块&quot;。</p><hr><h2 id="七、串联" tabindex="-1">七、串联 <a class="header-anchor" href="#七、串联" aria-label="Permalink to &quot;七、串联&quot;">​</a></h2><p>把这一篇接回整条主线:</p><ul><li><strong>承接第 04 篇(Tick 系统)</strong>:第 04 篇讲的&quot;单 tick 内执行顺序&quot;,实体 tick 是其中独立且通常最重的一步。方块靠随机刻抽样、靠邻居通知被动更新;实体则是<strong>每个都主动跑一遍</strong>——这正是两者性能特征不同的根因。</li><li><strong>对比第 09 篇(方块三层)</strong>:那一篇会讲 Block / BlockState / 方块实体。注意&quot;方块实体&quot;名字里有&quot;实体&quot;二字,但它<strong>本质是方块的附加数据</strong>,绑定在网格上、靠数组隐含位置;和本篇的 Entity 是<strong>两类东西</strong>。把这两个概念分清,是理解 Minecraft 数据模型的关键一关。</li><li><strong>接续第 10 篇(物品等其它对象)</strong>:物品 ItemStack 平时寄生在容器里,一旦掉到地上,就被一个 <code>ItemEntity</code>(本篇层级树里的一支)装着进入世界——实体在这里成了&quot;物品进入世界的载体&quot;。</li></ul><p>呼应贯穿全系列的那句主线:方块的省来自&quot;能共享就不复制、位置能隐含就不存&quot;;而实体恰恰是<strong>不能共享、位置必须显式存、每个都得单独跑</strong>的那一类——理解了这个反差,就理解了为什么 Minecraft 的性能优化总是围着&quot;少放实体&quot;打转。</p>`,48)])])}const h=o(s,[["render",i]]);export{p as __pageData,h as default};
